import{_ as o,o as r,c as a,a2 as d}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[LOGIC / BUSINESS] F-06.2 — Detalle, Crear y Editar Código de Error","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-06.2_error_codes_detalle_crud.md","filePath":"backlog/F-06.2_error_codes_detalle_crud.md","lastUpdated":null}'),t={name:"backlog/F-06.2_error_codes_detalle_crud.md"};function c(i,e,n,s,l,u){return r(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="logic-business-f-06-2-—-detalle-crear-y-editar-codigo-de-error" tabindex="-1">[LOGIC / BUSINESS] F-06.2 — Detalle, Crear y Editar Código de Error <a class="header-anchor" href="#logic-business-f-06-2-—-detalle-crear-y-editar-codigo-de-error" aria-label="Permalink to &quot;[LOGIC / BUSINESS] F-06.2 — Detalle, Crear y Editar Código de Error&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-06 — Catálogo de Códigos de Error (CRUD)</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Logic / Business</code><strong>Secundaria:</strong> <code>Data</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel + Base de Datos)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-06.1_error_codes_index.html">F-06.1</a></td><td>Listado de error codes funcional; el detalle/edición es su continuación directa</td></tr><tr><td><a href="./F-00.2_migraciones_modelos.html">F-00.2</a></td><td>Tabla <code>error_codes</code> con constraint <code>UNIQUE (code, app_source)</code> en BD</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero poder crear nuevos códigos de error, editar los existentes y borrarlos Para mantener actualizado el catálogo de errores conocidos del sistema</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Crear error code):</strong> Dado que relleno el formulario de creación (Código, Aplicación, Nombre, Descripción opcional, Fichero opcional, Línea opcional) y pulso &quot;Guardar&quot;, cuando el formulario es válido, entonces se crea el registro en <code>error_codes</code> y se redirige al detalle del nuevo código con un flash message de confirmación.</li><li>[ ] <strong>Escenario 2 (Validación clave compuesta):</strong> Dado que intento crear un error code con la misma combinación <code>(code, app_source)</code> que ya existe, cuando se envía el formulario, entonces se muestra un error de validación &quot;Ya existe un código con este ID para esta aplicación&quot; y no se duplica.</li><li>[ ] <strong>Escenario 3 (Editar error code):</strong> Dado que estoy en la vista de detalle de un error code y pulso &quot;Editar&quot;, cuando se activa el modo edición, entonces los campos se vuelven editables. Al guardar, se actualiza el registro y se muestra confirmación.</li><li>[ ] <strong>Escenario 4 (Borrar error code):</strong> Dado que pulso &quot;Borrar&quot; en el detalle de un error code, cuando confirmo el modal (Alpine.js), entonces se borra el registro de <code>error_codes</code> (y <code>error_code_comments</code> en cascade) y se redirige al listado.</li><li>[ ] <strong>Escenario 5 (Validaciones de campos):</strong> <code>code</code>: requerido, max 50. <code>app_source</code>: requerido, max 100. <code>name</code>: requerido, max 200. <code>description</code>: opcional, max 5000. <code>file</code>: opcional, max 255. <code>line</code>: opcional, entero positivo.</li><li>[ ] <strong>Requisito Técnico:</strong> Componente Livewire <code>ErrorCodeForm</code> con dos modos: create y edit. Ruta <code>GET /error-codes/create</code> para crear y <code>GET /error-codes/{id}</code> para detalle/editar. <code>ErrorCodeController@store</code> y <code>ErrorCodeController@update</code> con <code>FormRequest ErrorCodeRequest</code>. Unique rule en validación: <code>Rule::unique(&#39;error_codes&#39;)-&gt;where(&#39;app_source&#39;, $this-&gt;app_source)-&gt;ignore($this-&gt;errorCodeId)</code>.</li></ul><hr><p><strong>MoSCoW:</strong> <code>MUST</code><strong>Sprint:</strong> Sprint 2</p><p><strong>Notas:</strong></p><ul><li>La clave compuesta <code>(code, app_source)</code> es la clave de negocio que identifica de forma única un tipo de error dentro de una aplicación.</li><li>El campo <code>line</code> es orientativo — puede cambiar entre versiones del código. No es obligatorio.</li><li>El borrado en cascade garantiza que al eliminar un error code, también se eliminan sus comentarios.</li></ul>',16)])])}const m=o(t,[["render",c]]);export{g as __pageData,m as default};
